import{_ as d,o,c as r,a2 as e}from"./chunks/framework.DZO5kRrk.js";const p=JSON.parse('{"title":"证件照工坊 MVP 开发拆解计划","description":"","frontmatter":{},"headers":[],"relativePath":"id-photo-workshop-plan.md","filePath":"id-photo-workshop-plan.md"}'),a={name:"id-photo-workshop-plan.md"};function n(s,t,h,i,l,c){return o(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="证件照工坊-mvp-开发拆解计划" tabindex="-1">证件照工坊 MVP 开发拆解计划 <a class="header-anchor" href="#证件照工坊-mvp-开发拆解计划" aria-label="Permalink to &quot;证件照工坊 MVP 开发拆解计划&quot;">​</a></h1><p><strong>目标</strong>：跑通核心闭环，完成最小可行性产品上架。 <strong>原则</strong>：先验证最大技术风险，再堆叠业务逻辑，最后铺 UI。</p><hr><h2 id="阶段零-技术-命门-验证-最重要-必须先做" tabindex="-1">阶段零：技术&quot;命门&quot;验证（最重要，必须先做） <a class="header-anchor" href="#阶段零-技术-命门-验证-最重要-必须先做" aria-label="Permalink to &quot;阶段零：技术&quot;命门&quot;验证（最重要，必须先做）&quot;">​</a></h2><p>这是整个 App 成立的基础。如果这步走不通，项目直接终止或转向。</p><table tabindex="0"><thead><tr><th>任务</th><th>目标</th><th>验证标准</th></tr></thead><tbody><tr><td><strong>0.1 跑通环境</strong></td><td>安装 DevEco Studio，创建纯血鸿蒙 Demo</td><td>能在真机/云真机上跑出 Hello World</td></tr><tr><td><strong>0.2 核心抠图验证</strong></td><td>调用 <code>Core Vision Kit</code> 的人像分割能力</td><td>传入一张带背景的人像照，能返回精准的透明底 PNG</td></tr><tr><td><strong>0.3 简单合成验证</strong></td><td>用 <code>Canvas</code> 或 <code>Image</code> 组件</td><td>能将返回的透明底 PNG 叠在红色/蓝色背景上并显示</td></tr></tbody></table><hr><h2 id="阶段一-底层核心能力封装-不写界面-只写工具类" tabindex="-1">阶段一：底层核心能力封装（不写界面，只写工具类） <a class="header-anchor" href="#阶段一-底层核心能力封装-不写界面-只写工具类" aria-label="Permalink to &quot;阶段一：底层核心能力封装（不写界面，只写工具类）&quot;">​</a></h2><p>把图像处理的脏活累活封装成纯净的函数，方便后续页面调用。</p><table tabindex="0"><thead><tr><th>任务</th><th>目标</th><th>输入输出</th></tr></thead><tbody><tr><td><strong>1.1 图片读取与转换</strong></td><td>封装 fileIo，处理相册选图</td><td><code>uri</code> -&gt; <code>PixelMap</code></td></tr><tr><td><strong>1.2 尺寸裁剪引擎</strong></td><td>封装 Image Kit 的 crop 接口</td><td><code>PixelMap</code> + 目标宽高(px) -&gt; 新 <code>PixelMap</code></td></tr><tr><td><strong>1.3 背景替换引擎</strong></td><td>整合 Core Vision Kit + 底色填充</td><td><code>PixelMap</code> + 颜色值 -&gt; 新 <code>PixelMap</code></td></tr><tr><td><strong>1.4 迭代压缩引擎</strong></td><td>二分法压缩图片大小</td><td><code>PixelMap</code> + 目标大小(KB) -&gt; 满足大小的二进制流</td></tr><tr><td><strong>1.5 图片保存封装</strong></td><td>封装保存到相册/文件的操作</td><td>二进制流 -&gt; 保存成功提示</td></tr></tbody></table><hr><h2 id="阶段二-业务数据与逻辑架构" tabindex="-1">阶段二：业务数据与逻辑架构 <a class="header-anchor" href="#阶段二-业务数据与逻辑架构" aria-label="Permalink to &quot;阶段二：业务数据与逻辑架构&quot;">​</a></h2><p>搭建脱离 UI 的业务流。</p><table tabindex="0"><thead><tr><th>任务</th><th>目标</th><th>详情</th></tr></thead><tbody><tr><td><strong>2.1 构造尺寸数据库</strong></td><td>建立 <code>spec-db.json</code></td><td>包含：名称、宽(px)、高(px)、背景色要求、文件大小(KB)限制</td></tr><tr><td><strong>2.2 状态管理设计</strong></td><td>定义全局状态/页面级状态</td><td>当前选中的尺寸、原始原图、抠图后的图、最终生成的图</td></tr></tbody></table><hr><h2 id="阶段三-mvp-ui-开发-拼积木" tabindex="-1">阶段三：MVP UI 开发（拼积木） <a class="header-anchor" href="#阶段三-mvp-ui-开发-拼积木" aria-label="Permalink to &quot;阶段三：MVP UI 开发（拼积木）&quot;">​</a></h2><p>基于 ArkUI 构建最简陋但可用的界面。</p><table tabindex="0"><thead><tr><th>任务</th><th>页面/组件</th><th>功能点</th></tr></thead><tbody><tr><td><strong>3.1 首页 (尺寸列表)</strong></td><td><code>Index.ets</code></td><td>读取 JSON 渲染列表、支持关键词搜索、点击进入制作页</td></tr><tr><td><strong>3.2 制作页 (相机/相册)</strong></td><td><code>Make.ets</code></td><td>调起相册/相机选图、显示原图预览</td></tr><tr><td><strong>3.3 处理中态 (Loading)</strong></td><td><code>LoadingDialog</code></td><td>显示&quot;正在智能抠图...&quot; (抠图耗时，必须有阻断式 loading)</td></tr><tr><td><strong>3.4 效果预览与微调</strong></td><td><code>Preview.ets</code></td><td>上方显示合成图；下方提供底色切换（红/蓝/白）按钮</td></tr><tr><td><strong>3.5 结果保存页</strong></td><td><code>Result.ets</code></td><td>显示最终大小，提供&quot;保存到相册&quot;按钮，触发压缩逻辑</td></tr></tbody></table><hr><h2 id="阶段四-上架准备-非技术工作" tabindex="-1">阶段四：上架准备（非技术工作） <a class="header-anchor" href="#阶段四-上架准备-非技术工作" aria-label="Permalink to &quot;阶段四：上架准备（非技术工作）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>任务</th><th>内容</th></tr></thead><tbody><tr><td><strong>4.1 隐私合规</strong></td><td>编写用户协议和隐私政策（声明纯本地处理，不上传照片）</td></tr><tr><td><strong>4.2 素材准备</strong></td><td>图标设计(1个)、应用市场截图(3-5张)、应用描述(突出免费、纯本地)</td></tr><tr><td><strong>4.3 资质与上架</strong></td><td>申请开发者认证、提包审核</td></tr></tbody></table><hr><h2 id="执行建议" tabindex="-1">执行建议 <a class="header-anchor" href="#执行建议" aria-label="Permalink to &quot;执行建议&quot;">​</a></h2><ol><li><strong>绝对不要一上来就写 UI</strong>：如果 Core Vision Kit 的抠图效果奇差无比，你前面画的页面全废了。</li><li><strong>第一周的任务只有阶段零</strong>：想尽一切办法（买二手手机/借/云测），把阶段零跑通。跑通了，这个项目成功了 60%。</li></ol>',24)])])}const b=d(a,[["render",n]]);export{p as __pageData,b as default};
